  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '门锁id',
  `yard_sn` varchar(191) DEFAULT NULL COMMENT '园区sn（第三方）',
  `door_guid` varchar(191) DEFAULT NULL COMMENT '门禁id（第三方）',
  `door_name` varchar(191) DEFAULT NULL COMMENT '门禁名称（第三方）',
