  `city_name` varchar(191) DEFAULT NULL COMMENT '市名',
  `county_name` varchar(191) DEFAULT NULL COMMENT '区名',
  `detail_info` varchar(191) DEFAULT NULL COMMENT '详情地址',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='门锁表';
