DROP TABLE IF EXISTS `mx_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mx_user` (
  `user_id` bigint NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `create_time` datetime(3) DEFAULT NULL,
  `update_time` datetime(3) DEFAULT NULL,
  `latest_checkup_date_time` datetime(3) DEFAULT NULL COMMENT '最近检查日期',
  `name` varchar(24) DEFAULT '' COMMENT '姓名',
  `gender` int DEFAULT '1' COMMENT '性别 1:男性 0:女性',
  `date_of_birth` date DEFAULT NULL COMMENT '出生年月',
  `age` int DEFAULT NULL COMMENT '年龄',
  `phone_number` varchar(50) NOT NULL COMMENT '手机号码',
  `password` varchar(255) NOT NULL DEFAULT '' COMMENT '密码',
  `qq_number` varchar(50) DEFAULT '' COMMENT 'qq号',
  `email_address` varchar(50) DEFAULT '' COMMENT '邮箱',
  `identification_number` varchar(50) DEFAULT '' COMMENT '身份证号',
  `wechat` varchar(50) DEFAULT '' COMMENT '微信',
  `openid` varchar(100) DEFAULT '' COMMENT '微信openid',
  `unionid` varchar(100) DEFAULT '' COMMENT '微信unionid',
  `avatar_url` varchar(500) DEFAULT '' COMMENT '微信头像',
  `wx_nick_name` varchar(200) DEFAULT '' COMMENT '微信昵称',
  `wx_phone` varchar(50) DEFAULT '' COMMENT '微信手机号',
  `subscribe_time` datetime(3) DEFAULT NULL COMMENT '关注时间',
  `user_role` int DEFAULT '0' COMMENT '用户身份0普通顾客1店长2验光师',
  `medical_insurance_account` varchar(50) DEFAULT '' COMMENT '医保账号',
  `city` varchar(50) DEFAULT '' COMMENT '城市',
  `contact_address` varchar(500) DEFAULT '' COMMENT '联系地址',
  `occupation` varchar(50) DEFAULT '' COMMENT '职业',
  `company` varchar(50) DEFAULT '' COMMENT '单位',
  `remarks` varchar(500) DEFAULT '' COMMENT '备注',
  `glasses_need` varchar(50) DEFAULT '' COMMENT '配镜需求',
  `dominant_eye` varchar(50) DEFAULT '' COMMENT '主视眼',
  `is_delete` int DEFAULT '0' COMMENT '逻辑删0否1是',
  PRIMARY KEY (`user_id`) USING BTREE,
  UNIQUE KEY `u_p` (`phone_number`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='用户信息表';
