CREATE TABLE `mx_user_flow` (
  `flow_id` int NOT NULL AUTO_INCREMENT COMMENT '流程ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `create_time` datetime(3) DEFAULT NULL,
  `update_time` datetime(3) DEFAULT NULL,
  `type` int NOT NULL COMMENT '分类',
  `xm_iconid` int DEFAULT NULL COMMENT '视图id',
  `left_eye_glassid` int DEFAULT NULL COMMENT '左眼镜片ID',
  `right_eye_glassid` int DEFAULT NULL COMMENT '右眼镜片ID',
  `detection_eye` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '检测眼',
  `dial_option` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '拨盘选项',
  `far_nearly_use` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '远近用',
  `fog_vision` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '雾视',
  PRIMARY KEY (`flow_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='用户流程表';
