DROP TABLE IF EXISTS `optometry_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `optometry_records` (
  `optometry_records_id` bigint NOT NULL AUTO_INCREMENT COMMENT '验光记录ID',
  `create_time` datetime(3) DEFAULT NULL,
  `update_time` datetime(3) DEFAULT NULL,
  `customer_id` bigint DEFAULT NULL COMMENT '顾客ID',
  `customer_name` varchar(255) NOT NULL COMMENT '顾客姓名',
  `optometrist_id` bigint NOT NULL COMMENT '验光师ID',
  `optometrist_name` varchar(255) DEFAULT NULL COMMENT '验光师姓名',
  `store_id` bigint NOT NULL COMMENT '门店ID',
  `store_name` varchar(255) NOT NULL COMMENT '门店名称',
  `store_phone` varchar(20) NOT NULL COMMENT '门店电话',
  `is_delete` int NOT NULL DEFAULT '0' COMMENT '逻辑删0否1是',
  `ai_data` varchar(2000) DEFAULT NULL COMMENT 'ai数据',
  PRIMARY KEY (`optometry_records_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='验光记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

